//webMI.data.subscribeBlock([webMI.query["temp"+pointnum],webMI.query["hum"+pointnum]], [],  function(e) {

webMI.data.subscribeBlock([webMI.query["temp"],webMI.query["min"],webMI.query["max"],webMI.query["setpoint"],webMI.query["rel_abs"]], [],  function(e) {

	var Te = e[0].value;
	var Mi = e[1].value;
	var Ma = e[2].value;
	var Sp = e[3].value;
	var RA = e[4].value;
	var SetlblPos = 0;
	var AHupPos = 0;
	var AHdownPos = 0;
	var ALupPos = 0;
	var ALdownPos = 0;
	var AH1RlblPos = 0;
	var AL1RlblPos = 0;
	var AL1R1lblH = 0;
	var Miv = 0;
	var Mav = 0;

	//Check if values are relative to setpoint or absolute

	if (RA == false) {
		Miv = Sp - Mi;
		Mav = Sp + Ma;
		webMI.gfx.setVisible("AHup",true);
		webMI.gfx.setVisible("AHdown",true);
		webMI.gfx.setVisible("ALup",true);
		webMI.gfx.setVisible("ALdown",true);
		webMI.gfx.setVisible("AH1Rlbl",true);
		webMI.gfx.setVisible("AL1Rlbl",true);
		webMI.gfx.setVisible("AH1Albl",false);
		webMI.gfx.setVisible("AL1Albl",false);
	}
	else {
		Miv = Mi;
		Mav = Ma;
		webMI.gfx.setVisible("AHup",false);
		webMI.gfx.setVisible("AHdown",false);
		webMI.gfx.setVisible("ALup",false);
		webMI.gfx.setVisible("ALdown",false);
		webMI.gfx.setVisible("AH1Albl",true);
		webMI.gfx.setVisible("AL1Albl",true);
		webMI.gfx.setVisible("AH1Rlbl",false);
		webMI.gfx.setVisible("AL1Rlbl",false);
	}

	//Set the scale Min and Max values after the check
	webMI.gfx.setText("scale_max", Mav);
	webMI.gfx.setText("scale_min", Miv);

	//Set the scale value
	webMI.gfx.setScaleY("bar", webMI.translate(Te, Miv, Mav, 0, 1));

	//Sepoint line position
	yPos = parseFloat(webMI.gfx.getCenterY("point55_0")) - webMI.translate(Sp,Miv,Mav,0,parseFloat(webMI.gfx.getCenterY("point55_0"))-parseFloat(webMI.gfx.getCenterY("point55_30")));
	webMI.gfx.setY1("Setline",yPos);
	webMI.gfx.setY2("Setline",yPos);

	SetlblPos = yPos - parseFloat(webMI.gfx.getHeight("Setlbl"))/2;
	webMI.gfx.setY("Setlbl",SetlblPos);

	//Ranges height and labels position
	AHupPos = parseFloat(webMI.gfx.getY1("AHline"));
	webMI.gfx.setY("AHup",AHupPos);
	AHdownPos = parseFloat(webMI.gfx.getY1("Setline"))-parseFloat(webMI.gfx.getHeight("AHdown"));
	webMI.gfx.setY("AHdown",AHdownPos);
	AH1RlblPos = parseFloat(webMI.gfx.getY1("Setline"))-parseFloat(webMI.gfx.getHeight("AH1Rlbl"))/2-webMI.translate(50,0,100,0,parseFloat(webMI.gfx.getY1("Setline"))-parseFloat(webMI.gfx.getY1("AHline")));
	webMI.gfx.setY("AH1Rlbl",AH1RlblPos);

	ALupPos = parseFloat(webMI.gfx.getY1("Setline"));
	webMI.gfx.setY("ALup",ALupPos);
	ALdownPos = parseFloat(webMI.gfx.getY1("ALline"))-parseFloat(webMI.gfx.getHeight("ALdown"));
	webMI.gfx.setY("ALdown",ALdownPos);
	AL1RlblPos = parseFloat(webMI.gfx.getY1("ALline"))-parseFloat(webMI.gfx.getHeight("AL1Rlbl"))/2-webMI.translate(50,0,100,0,parseFloat(webMI.gfx.getY1("ALline"))-parseFloat(webMI.gfx.getY1("Setline")));
	webMI.gfx.setY("AL1Rlbl",AL1RlblPos);

});

